export const renderItemSvg = (item: string, selecteds: string[]) => {
  return selecteds.includes(item)
    ? (teethItems as Record<string, any>)[item]?.selected
    : (teethItems as Record<string, any>)[item]?.svg;
};

export const getAnatomyBodyPartItemIds = (items: string[]): string[] => {
  if (!items) return [];
  const topJaw = items.some((t) => t === "1-2" || t === "5-6");
  const bottomJaw = items.some((t) => t === "3-4" || t === "7-8");
  if (topJaw && bottomJaw) return ["1"];
  if (topJaw) return ["2"];
  if (bottomJaw) return ["3"];
  return (
    items.map(
      (t) => (teethItems as Record<string, any>)[t].AnatomyBodyPartItemId,
    ) ?? []
  );
};

export const getItemIdsByAnatomyBodyPartItemId = (
  ids: string[],
  teethType: string,
): string[] => {
  if (!ids) return [];
  if (ids.includes("1")) {
    return teethType === "1" ? ["1-2", "3-4"] : ["5-6", "7-8"];
  }
  if (ids.includes("2")) {
    return teethType === "1" ? ["1-2"] : ["5-6"];
  }
  if (ids.includes("3")) {
    return teethType === "1" ? ["3-4"] : ["7-8"];
  }
  return ids.map(
    (id) =>
      Object.keys(teethItems).find(
        (key) =>
          (teethItems as Record<string, any>)[key].AnatomyBodyPartItemId === id,
      ) ?? "",
  );
};

export const getTeethLabels = (ids: string[]): string[] => {
  if (
    ids.some((t) => t === "1-2" || t === "5-6") &&
    ids.some((t) => t === "3-4" || t === "7-8")
  )
    return ["CH"];
  return (
    ids?.map((t) => {
      if (t === "1-2" || t === "5-6") return "HT";
      if (t === "3-4" || t === "7-8") return "HD";
      return `R${t}`;
    }) || []
  );
};
